def jaccard_similarity(text_a: str, text_b: str) -> float:
    """Token-level Jaccard similarity between two strings."""
    def tokenise(text: str) -> set[str]:
        return set(re.findall(r"\b\w+\b", text.lower()))
    a, b = tokenise(text_a), tokenise(text_b)
    if not a or not b:
        return 0.0
    return len(a & b) / len(a | b)


def find_potential_duplicates(
    new_request: IntakeRequest,
    existing_requests: list[IntakeRequest],
    threshold: float = 0.35,
) -> list[tuple[IntakeRequest, float]]:
    """Return existing requests with similarity above threshold, sorted by score."""
    scores = []
    new_text = new_request.title + " " + new_request.problem_statement
    for existing in existing_requests:
        if existing.request_id == new_request.request_id:
            continue
        existing_text = existing.title + " " + existing.problem_statement
        score = jaccard_similarity(new_text, existing_text)
        if score >= threshold:
            scores.append((existing, score))
    return sorted(scores, key=lambda x: x[1], reverse=True)

@dataclasses.dataclass
class ScoredRequest:
    request: IntakeRequest
    business_value_score: float    # 1–10: estimated annual value / impact
    strategic_alignment_score: float  # 1–10: alignment with OKRs
    urgency_score: float           # 1–10: time sensitivity
    implementation_effort_score: float  # 1–10: lower effort = higher score (10 = easy)
    risk_score: float              # 1–10: lower risk = higher score (10 = no risk)

    WEIGHTS = {
        "business_value": 0.35,
        "strategic_alignment": 0.25,
        "urgency": 0.20,
        "implementation_effort": 0.10,
        "risk": 0.10,
    }

    @property
    def composite_score(self) -> float:
        w = self.WEIGHTS
        return (
            self.business_value_score * w["business_value"]
            + self.strategic_alignment_score * w["strategic_alignment"]
            + self.urgency_score * w["urgency"]
            + self.implementation_effort_score * w["implementation_effort"]
            + self.risk_score * w["risk"]
        )

    @property
    def priority_tier(self) -> str:
        s = self.composite_score
        if s >= 8.0:
            return "P1-Fast-Track"
        if s >= 6.0:
            return "P2-Next-Cohort"
        if s >= 4.0:
            return "P3-Backlog"
        return "P4-Deferred"

    def format_scorecard(self) -> str:
        return (
            f"Request: {self.request.title}\n"
            f"  Business value: {self.business_value_score:.1f}/10\n"
            f"  Strategic alignment: {self.strategic_alignment_score:.1f}/10\n"
            f"  Urgency: {self.urgency_score:.1f}/10\n"
            f"  Implementation effort: {self.implementation_effort_score:.1f}/10\n"
            f"  Risk: {self.risk_score:.1f}/10\n"
            f"  COMPOSITE: {self.composite_score:.2f}/10  →  {self.priority_tier}"
        )
